import re
text = open('/Users/gbang/Downloads/algora/workspace/e0b7b7da-d5e7-41cb-a9fb-54724ba4c822_hld/_response.md').read()
lines = text.split('\n')
blocks=[]
inb=False; cur=[]; start=0
for i,l in enumerate(lines, start=1):
    if l.strip()=='```mermaid':
        inb=True; cur=[]; start=i; continue
    if inb and l.strip()=='```':
        inb=False; blocks.append(cur); continue
    if inb: cur.append((i,l))

issues=[]
for cur in blocks:
    for ln,content in cur:
        # 1) Any colon or semicolon anywhere is dangerous in mermaid text
        if ':' in content or ';' in content:
            issues.append((ln,'colon/semicolon',content))
        # 2) Find UNQUOTED node labels [ ... ] and check for breaking chars
        # node label patterns: NODE[...], NODE[(...)], NODE[[...]]
        # extract bracket contents that are NOT quote-wrapped
        # square node labels: word[label]  -- but not [( or [[
        for m in re.finditer(r'[A-Za-z0-9_]+\[(?!\[|\()([^\]]*)\]', content):
            lbl=m.group(1)
            if lbl.startswith('"') and lbl.endswith('"'):
                continue  # quoted, safe
            for ch in '():/;<>{}':
                if ch in lbl:
                    issues.append((ln,f'unquoted square-label has [{ch}]',content)); break
        # 3) cylinder [( ... )] contents
        for m in re.finditer(r'\[\(([^\)]*)\)\]', content):
            lbl=m.group(1)
            if lbl.startswith('"'): continue
            for ch in '():/;<>{}':
                if ch in lbl:
                    issues.append((ln,f'unquoted cylinder has [{ch}]',content)); break
        # 4) subroutine [[ ... ]]
        for m in re.finditer(r'\[\[([^\]]*)\]\]', content):
            lbl=m.group(1)
            if lbl.startswith('"'): continue
            for ch in '():/;<>{}':
                if ch in lbl:
                    issues.append((ln,f'unquoted subroutine has [{ch}]',content)); break
        # 5) edge text |...| not quoted with breaking char
        for m in re.finditer(r'\|([^|]*)\|', content):
            et=m.group(1)
            if et.startswith('"') and et.endswith('"'):
                continue
            for ch in '():/;<>{}':
                if ch in et:
                    issues.append((ln,f'unquoted edge-text has [{ch}]',content)); break

if not issues:
    print("NO REAL BREAKING-CHAR ISSUES FOUND (all parens/quotes are in legitimate node-shape or quoted positions).")
else:
    for ln,kind,c in issues:
        print(f"L{ln} :: {kind} :: {c}")
